texttool_globals_toast___slider_adjustment_button_disabled_reason = TextObject(bs_BA="Granica postavki je dostignuta.", cs_CZ="Limit nastavení byl dosažen.", da_DK="Indstillingsgrænse blev nået.", de_DE="Einstellungslimit wurde erreicht.", el_GR="Επιτεύχθηκε το όριο ρύθμισης.", en_GB="Settings limit reached.", es_ES="Se ha alcanzado el límite del ajuste.", fi_FI="Asetusraja saavutettiin.", fr_FR="La limite de réglage a été atteinte.", hr_HR="Dostignut je limit postavki.", hu_HU="Beállítási határérték elérve.", it_IT="È stato raggiunto il limite di impostazione.", nl_NL="De instellingenlimiet is bereikt.", no_NO="Innstillingsgrense er nådd.", pl_PL="Limit ustawienia został osiągnięty.", pt_PT="O limite de regulação foi atingido.", ro_RO="A fost atinsă limita de setare.", ru_RU="Предел настройки достигнут.", sk_SK="Limit nastavenia sa dosiahol.", sl_SI="Omejitev nastavitve je bila dosežena.", sr_RS="Dostignuta je granica podešavanja.", sv_SE="Inställningsgränsen har nåtts.", tr_TR="Ayarlama limitine ulaşıldı.", uk_UA="Ліміт налаштування досягнуто.")
